mapper.select:
SELECT * FROM registration
WHERE id = #{id}
LIMIT 1

SELECT * FROM registration
WHERE activity_id = #{activityId} AND user_id = #{userId}
LIMIT 1

SELECT r.id, r.activity_id, a.title AS activity_title, r.user_id, u.username, u.real_name, r.position_id, p.name AS position_name, r.status, r.remark, r.score, r.created_at FROM registration r LEFT JOIN activity a ON a.id = r.activity_id AND a.deleted = 0 LEFT JOIN sys_user u ON u.id = r.user_id AND u.deleted = 0 LEFT JOIN `position` p ON p.id = r.position_id AND p.deleted = 0 WHERE r.user_id = #{userId}
AND r.status = #{query.status}
ORDER BY r.created_at DESC LIMIT #{query.offset}, #{query.pageSize}

SELECT COUNT(*) FROM registration r
WHERE r.user_id = #{userId}

    AND r.status = #{query.status}

SELECT r.id, r.activity_id, a.title AS activity_title, r.user_id, u.username, u.real_name, r.position_id, p.name AS position_name, r.status, r.remark, r.score, r.created_at FROM registration r LEFT JOIN activity a ON a.id = r.activity_id AND a.deleted = 0 LEFT JOIN sys_user u ON u.id = r.user_id AND u.deleted = 0 LEFT JOIN `position` p ON p.id = r.position_id AND p.deleted = 0 WHERE r.activity_id = #{activityId}
AND r.status = #{query.status}
ORDER BY r.created_at DESC LIMIT #{query.offset}, #{query.pageSize}

SELECT COUNT(*) FROM registration r
WHERE r.activity_id = #{activityId}

    AND r.status = #{query.status}

